<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{api}from'../api/client';import type{Book,BookPage}from'../types/book';const books=ref<Book[]>([]);const total=ref(0);const loading=ref(false);const query=reactive({keyword:'',format:'',reading_status:'',sort:'created_at',order:'desc',page:1,page_size:20});async function load(){loading.value=true;try{const{data}=await api.get<BookPage>('/books',{params:query});books.value=data.items;total.value=data.total}finally{loading.value=false}}function cover(book:Book){return book.cover_path?`/api/v1/books/${book.id}/cover`:''}onMounted(load)</script>
<template><section><div class="title"><h1>我的书库</h1><el-button type="primary" @click="$router.push('/upload')">上传书籍</el-button></div><el-form inline><el-form-item><el-input v-model="query.keyword" clearable placeholder="标题、作者、ISBN、标签" @keyup.enter="load"/></el-form-item><el-form-item><el-select v-model="query.format" clearable placeholder="格式"><el-option v-for="f in ['epub','pdf','mobi','azw3','txt']" :key="f" :label="f.toUpperCase()" :value="f"/></el-select></el-form-item><el-form-item><el-select v-model="query.reading_status" clearable placeholder="阅读状态"><el-option label="未读" value="unread"/><el-option label="在读" value="reading"/><el-option label="已读" value="finished"/><el-option label="暂停" value="paused"/><el-option label="弃读" value="abandoned"/></el-select></el-form-item><el-button @click="query.page=1;load()">筛选</el-button></el-form><el-empty v-if="!loading&&!books.length" description="书库中还没有书籍"/><div v-loading="loading" class="grid"><el-card v-for="book in books" :key="book.id" shadow="hover" @click="$router.push(`/books/${book.id}`)"><img v-if="cover(book)" :src="cover(book)" class="cover"/><div v-else class="placeholder">{{book.title.slice(0,1)}}</div><h3>{{book.title}}</h3><p>{{book.authors.map(a=>a.name).join('、')||'未知作者'}}</p><el-tag v-for="file in book.files" :key="file.id" size="small">{{file.format.toUpperCase()}}</el-tag></el-card></div><el-pagination v-if="total>query.page_size" v-model:current-page="query.page" :page-size="query.page_size" :total="total" layout="prev, pager, next" @current-change="load"/></section></template>
<style scoped>.title{display:flex;align-items:center;justify-content:space-between}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:1rem;min-height:8rem}.el-card{cursor:pointer}.cover,.placeholder{width:100%;aspect-ratio:2/3;object-fit:cover;border-radius:4px}.placeholder{display:grid;place-items:center;background:#eef1f6;font-size:3rem;color:#909399}h3{margin:.75rem 0 .25rem}p{color:#909399;min-height:1.5em}.el-tag{margin-right:.3rem}</style>
